export const getCourierStates = (courier: CourierKey): string[] =>
  Object.keys(COURIER_OFFICES[courier] ?? {}).sort();

export const getCourierOffices = (courier: CourierKey, state: string): CourierOffice[] =>
  COURIER_OFFICES[courier]?.[state] ?? [];
